var e=[{id:`L9_1`,type:`dialog`,speaker:`BOMI_HB_NULL_NULL`,text:{KOREA:`스테이지 클리어했다옹~`,JPN:`ステージクリアだにゃ～。`,ENG:`We cleared the stage purrfectly!`,TWN:`通關啦～`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:{char_id:`BOMI_HB_NULL_NULL`,face:`UNIT_PRIDE`},C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`MIYA_HB_NULL_NULL`,text:{KOREA:`보셨죠, 시청자 여러분? 저희가 해냈......`,JPN:`見てくれました？　視聴者の皆さん！　ミヤたちの勝……`,ENG:`Did you see that, everyone? We did—`,TWN:`看到了嗎，各位觀眾朋友們？我們做的……`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:{char_id:`BOMI_HB_NULL_NULL`,face:`UNIT_PRIDE`},C:null,R:{char_id:`MIYA_HB_NULL_NULL`,face:`UNIT_LAUGH`}}}},{id:`L13_1`,type:`dialog`,speaker:`MIYA_HB_NULL_NULL`,text:{KOREA:`히악?! 무슨 소리죠?`,JPN:`ひえっ！？　何の音ですか？`,ENG:`Eeep?! What was that?`,TWN:`咿啊？！妳說什麼？`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:{char_id:`BOMI_HB_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`MIYA_HB_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L15_1`,type:`dialog`,speaker:`CHOIENA_HB_NULL_NULL`,text:{KOREA:`중형 침식체야!`,JPN:`中型侵食体よ！`,ENG:`It's a heavy C.O.!`,TWN:`是中型侵蝕體！`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`CHOIENA_HB_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`CHOIENA_HB_NULL_NULL`,text:{KOREA:`동선은 드론으로 마킹할게. 다들 협동해서 멋진 피날레 보여주도록 해. `,JPN:`動線はドローンでマーキングするから、全員のコンビネーションで
最高のフィナーレを飾ってみせて。 `,ENG:`I'll mark its movements with the drone. Work as a team and show us the grand finale. `,TWN:`已經用無人機標記好路線了，大家同心協力，一起演出最棒的終章吧。`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`CHOIENA_HB_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`MIYA_HB_NULL_NULL`,text:{KOREA:`네...... 네!`,JPN:`は……はい！`,ENG:`Okay... Okay!`,TWN:`好……好的！`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:{char_id:`MIYA_HB_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:`RUMI_HB_NULL_NULL`,text:{KOREA:`다들 비켜! 저건 내가 잡겠어!`,JPN:`みんな下がってなさい！　あれはアタシの獲物よ！`,ENG:`Everyone, out of my way! That thing is mine!`,TWN:`大家都讓開！那個由我來解決！`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:{char_id:`MIYA_HB_NULL_NULL`,face:`UNIT_SERIOUS`},C:{char_id:`RUMI_HB_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`MIYA_HB_NULL_NULL`,text:{KOREA:`앗! 루미야......! 혼자 가면 또 이나 언니한테 혼나!`,JPN:`あっ！　ルミ……！　一人で行ったら、またメグミさんに怒られちゃう！`,ENG:`Oh! Lumi! You're going to get in trouble if you go by yourself again!`,TWN:`啊！魯米……！妳一個人上的話又要被理娜姐姐罵了！`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:{char_id:`MIYA_HB_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:null}}},{id:`L29_1`,type:`dialog`,speaker:`RUMI_HB_NULL_NULL`,text:{KOREA:`후~`,JPN:`ふ～。`,ENG:`Phew...`,TWN:`呼～`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`RUMI_HB_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`RUMI_HB_NULL_NULL`,text:{KOREA:`자, 다들 똑똑히 봤겠지? 이 루미 님께서 제일 강한 녀석을 잡으셨단 말씀이야.`,JPN:`ほらね、みんなちゃんと見たでしょう？
このルミ様が一番強い敵を仕留めてみせたわ。`,ENG:`Did you see that, everyone? I took down the biggest and the baddest of them all.`,TWN:`好了，大家看得很清楚吧？是我魯米大人，把最強的傢伙解決掉了。`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`RUMI_HB_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L32_1`,type:`dialog`,speaker:null,text:{KOREA:`크르르르......`,JPN:`ガルルル……`,ENG:`Grrrr...`,TWN:`唔吼吼吼……`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`RUMI_HB_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L33_1`,type:`dialog`,speaker:`MIYA_HB_NULL_NULL`,text:{KOREA:`앗, 루미! 아직 살아있어! 위험......!`,JPN:`あっ、ルミ！　まだ生きてる！　危ないっ……！`,ENG:`Oh, Lumi! It's still alive! Watch—`,TWN:`啊，魯米！它還活著！危險……！`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`MIYA_HB_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L34_1`,type:`dialog`,speaker:`RUMI_HB_NULL_NULL`,text:{KOREA:`어......?`,JPN:`え……？`,ENG:`Huh?`,TWN:`啊……？`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`RUMI_HB_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};